#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e6+5;
struct Trie{int son[5],fail;}t[N];
int n,m,Cnt;
string s,st[N];bool vis[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int ID(char c){
    if(c=='E')return 1;
    if(c=='S')return 2;
    if(c=='W')return 3;
    if(c=='N')return 4;
    return 0;//不会走到这一步
}
void BuildTrie(string str){
    int now=0;
    for(char c:str){
        int x=ID(c);
        if(!t[now].son[x])
            t[now].son[x]=(++Cnt);
        now=t[now].son[x];
    }return;
}//建造 Trie 树
void CountFail(){
    queue<int> q;
    while(!q.empty())q.pop();
    t[0].fail=0;
    for(int i=1;i<=4;i++)if(t[0].son[i])
        t[t[0].son[i]].fail=0,q.push(t[0].son[i]);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=1;i<=4;i++)
            if(t[u].son[i])
                t[t[u].son[i]].fail=t[t[u].fail].son[i],
                q.push(t[u].son[i]);
            else t[u].son[i]=t[t[u].fail].son[i];
    }return;
}//求出每个节点的 fail 指针
void SolveStringS(){
    int now=0;
    for(char c:s){
        int x=ID(c);
        int tmp=t[now].son[x];
        while(tmp)vis[tmp]=1,tmp=t[tmp].fail;
        now=t[now].son[x];
    }return;
}//标记母串中出现过的字母
int SolStr(string str){
    int now=0,res=0,len=0;
    for(char c:str){
        ++len;int x=ID(c);
        now=t[now].son[x];
        if(vis[now])res=len;
    }return res;
}
int main(){
    n=read(),m=read();cin>>s;
    for(int i=1;i<=m;i++)
        {cin>>st[i];BuildTrie(st[i]);}
    CountFail();
    SolveStringS();
    for(int i=1;i<=m;i++)
        cout<<SolStr(st[i])<<"\n";
    return 0;
}
